    [Description("The search query to find information about")] string query)
{
    // Uses the DuckDuckGo HTML endpoint for real search results.
    // Replace with Bing/Google Search API for production use.
    Console.WriteLine($"\n  🌐 Searching: \"{query}\"");
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await httpClient.GetStringAsync(url);
        var results = ParseSearchResults(html, maxResults: 5);

        if (results.Count == 0)
        {
            return JsonSerializer.Serialize(new
            {
                query,
                message = "No results found. Try a different query.",
                results = Array.Empty<object>()
            });
        }

        Console.WriteLine($"  ✅ Found {results.Count} results");
        return JsonSerializer.Serialize(new { query, results },
            new JsonSerializerOptions { WriteIndented = true });
    }
    catch (Exception ex)
    {
        return JsonSerializer.Serialize(new
        {
            query,
            error = $"Search failed: {ex.Message}",
            results = Array.Empty<object>()
        });
    }
}

string TakeNote(
    [Description("Short title for the note")] string title,
    [Description("The note content")] string content)
{
    notebook.AddNote(title, content);
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note saved: '{title}' ({notebook.Count} total notes)";
}

string ReadNotes()
{
    Console.WriteLine($"  📖 Reading {notebook.Count} notes");
    return notebook.GetAllNotes();
}

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(topic)
        ? "Recent advances in quantum computing"
        : topic;
}

static List<SearchResult> ParseSearchResults(string html, int maxResults)
{
    var results = new List<SearchResult>();
    var snippetTag = "class=\"result__snippet\"";
    var titleTag = "class=\"result__a\"";
    var urlTag = "class=\"result__url\"";

    var position = 0;
    while (results.Count < maxResults)
    {
        var titleStart = html.IndexOf(titleTag, position, StringComparison.Ordinal);
        if (titleStart < 0) break;

        var title = ExtractTagContent(html, titleStart);
        var snippet = string.Empty;
        var url = string.Empty;

        var snippetStart = html.IndexOf(snippetTag, titleStart, StringComparison.Ordinal);
        if (snippetStart >= 0)
        {
            snippet = ExtractTagContent(html, snippetStart);
        }

        var urlStart = html.IndexOf(urlTag, titleStart, StringComparison.Ordinal);
        if (urlStart >= 0)
        {
            url = ExtractTagContent(html, urlStart).Trim();
            if (!url.StartsWith("http", StringComparison.OrdinalIgnoreCase))
            {
                url = "https://" + url;
            }
        }

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add(new SearchResult(
                StripHtml(title).Trim(),
                StripHtml(snippet).Trim(),
                url));
        }

        position = titleStart + 1;
    }

    return results;
}

static string ExtractTagContent(string html, int tagPosition)
{
    var closeTag = html.IndexOf('>', tagPosition);
    if (closeTag < 0) return string.Empty;
    var endTag = html.IndexOf('<', closeTag + 1);
    if (endTag < 0) return string.Empty;
    return html[(closeTag + 1)..endTag];
}

static string StripHtml(string input)
{
    var result = System.Text.RegularExpressions.Regex.Replace(input, "<[^>]+>", string.Empty);
    return System.Net.WebUtility.HtmlDecode(result);
}

