 // --- Define tools ---
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(
         SearchWebAsync,
         name: "search_web",
         description: "Search the web for information on a topic. Returns a list of results with titles, snippets, and URLs."),

     AIFunctionFactory.Create(
         TakeNote,
         name: "take_note",
         description: "Save a research note with a title and content. Use this to record key findings during research."),

     AIFunctionFactory.Create(
         ReadNotes,
         name: "read_notes",
         description: "Read all saved research notes to review what has been recorded so far."),
 };

 // --- Build the chat client ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Create the research agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Your job is to thoroughly research a given topic by:
         1. Searching the web for relevant information using the search_web tool.
         2. Taking notes on key findings using the take_note tool.
         3. Performing multiple searches to cover different aspects of the topic.
         4. Reading your notes with read_notes to review findings before summarizing.
         5. Providing a comprehensive, well-organized summary with key points and sources.

         Always perform at least 3 different searches to ensure broad coverage.
         Take notes as you discover important information.
         End with a clear summary of your findings.
