 sealed class Notebook
 {
     private readonly List<Note> _notes = [];

     public int Count => _notes.Count;
     public IReadOnlyList<Note> Notes => _notes;

     public void AddNote(string title, string content)
     {
         _notes.Add(new Note(title, content, DateTime.UtcNow));
     }

     public string GetAllNotes()
     {
         if (_notes.Count == 0)
             return "No notes have been taken yet.";

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"[Note {i + 1}] {n.Title}\n{n.Content}"));
     }
 }

 record Note(string Title, string Content, DateTime Timestamp);
 record SearchResult(string Title, string Snippet, string Url);
